import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
const requireAuth = vi.fn(() => ({
    apiKey: "current-key",
    serviceUrl: "https://test.invalid",
}));
const saveCredentials = vi.fn();
const readActiveStudioSession = vi.fn(() => null);
const clearActiveStudioSession = vi.fn();
const updateActiveStudioSession = vi.fn();
const killStudioWindow = vi.fn();
const killPollerProcess = vi.fn();
vi.mock("../config.js", () => ({
    requireAuth: (...a) => requireAuth(...a),
    saveCredentials: (...a) => saveCredentials(...a),
}));
vi.mock("../activeStudioSession.js", () => ({
    readActiveStudioSession: () => readActiveStudioSession(),
    clearActiveStudioSession: (...a) => clearActiveStudioSession(...a),
    updateActiveStudioSession: (...a) => updateActiveStudioSession(...a),
}));
vi.mock("../studioTeardown.js", () => ({
    killStudioWindow: (...a) => killStudioWindow(...a),
    killPollerProcess: (...a) => killPollerProcess(...a),
}));
import { runSwitchOrg } from "./switchOrg.js";
const platform = { loginHint: "/bitfab:setup login" };
let emitted;
let originalArgv;
function lastEvent() {
    return emitted[emitted.length - 1];
}
beforeEach(() => {
    vi.clearAllMocks();
    readActiveStudioSession.mockReturnValue(null);
    emitted = [];
    originalArgv = process.argv;
    vi.spyOn(process.stdout, "write").mockImplementation((chunk) => {
        for (const line of String(chunk).split("\n")) {
            if (line.trim()) {
                emitted.push(JSON.parse(line));
            }
        }
        return true;
    });
});
afterEach(() => {
    process.argv = originalArgv;
    vi.restoreAllMocks();
});
function setArgs(...args) {
    process.argv = ["node", "switchOrg.js", ...args];
}
describe("runSwitchOrg", () => {
    it("errors without switching when no target org id is given", async () => {
        const fetchSpy = vi.spyOn(globalThis, "fetch");
        const exitSpy = vi.spyOn(process, "exit").mockImplementation(((code) => {
            throw new Error(`exit:${code}`);
        }));
        setArgs();
        await expect(runSwitchOrg(platform)).rejects.toThrow("exit:1");
        expect(fetchSpy).not.toHaveBeenCalled();
        expect(saveCredentials).not.toHaveBeenCalled();
        exitSpy.mockRestore();
    });
    it("switches to a target org: saves the new key, clears Studio, returns the key for env sync", async () => {
        readActiveStudioSession.mockReturnValue({ sessionId: "sess-1" });
        vi.spyOn(globalThis, "fetch").mockResolvedValue(new Response(JSON.stringify({
            status: "switched",
            clerkOrganizationId: "org_b",
            organizationName: "B",
            apiKey: "new-key",
            apiKeyId: "key-id",
        }), { status: 200 }));
        setArgs("org_b");
        await runSwitchOrg(platform);
        expect(saveCredentials).toHaveBeenCalledWith("new-key");
        expect(killStudioWindow).toHaveBeenCalledWith("sess-1");
        expect(killPollerProcess).toHaveBeenCalledWith("sess-1");
        const event = lastEvent();
        expect(event).toMatchObject({
            event: "switched",
            status: "switched",
            clerkOrganizationId: "org_b",
            organizationName: "B",
            // The switched-org key is returned so the caller can sync the app's
            // runtime BITFAB_API_KEY: get_bitfab_api_key honors a process-env override
            // and can lag the just-completed switch, so this is the authoritative key.
            apiKey: "new-key",
        });
    });
    it("reports not-member without replacing the key", async () => {
        vi.spyOn(globalThis, "fetch").mockResolvedValue(new Response(JSON.stringify({ status: "not-member" }), { status: 200 }));
        setArgs("org_stranger");
        await runSwitchOrg(platform);
        expect(lastEvent()).toEqual({
            event: "not-member",
            clerkOrganizationId: "org_stranger",
        });
        expect(saveCredentials).not.toHaveBeenCalled();
        expect(clearActiveStudioSession).not.toHaveBeenCalled();
    });
    it("does not tear down Studio on already-aligned, even with an active session", async () => {
        // Regression: already-aligned means the org didn't change, so an active
        // Studio session is already bound to the right org and must not be killed.
        readActiveStudioSession.mockReturnValue({ sessionId: "sess-1" });
        vi.spyOn(globalThis, "fetch").mockResolvedValue(new Response(JSON.stringify({
            status: "already-aligned",
            clerkOrganizationId: "org_a",
            organizationName: "A",
            apiKey: "same-key",
            apiKeyId: "key-id",
        }), { status: 200 }));
        setArgs("org_a");
        await runSwitchOrg(platform);
        expect(saveCredentials).toHaveBeenCalledWith("same-key");
        expect(killStudioWindow).not.toHaveBeenCalled();
        expect(killPollerProcess).not.toHaveBeenCalled();
        expect(clearActiveStudioSession).not.toHaveBeenCalled();
        expect(lastEvent()).toMatchObject({
            event: "switched",
            status: "already-aligned",
        });
    });
});
